import pg from "pg";

const SCHEMA = "astbench_shallow_postgres_norm_claude_code_r1";
const client = new pg.Client({
  host: "127.0.0.1",
  port: 5433,
  user: "lab",
  password: "lab",
  database: "sql_hidden_cost",
});

await client.connect();

// 1. List all tables
const tables = await client.query(
  `SELECT table_name FROM information_schema.tables WHERE table_schema = $1 ORDER BY table_name`,
  [SCHEMA]
);
console.log("=== TABLES ===");
console.log(tables.rows.map((r) => r.table_name).join(", "));

// 2. For each table, show columns
for (const { table_name } of tables.rows) {
  const cols = await client.query(
    `SELECT column_name, data_type FROM information_schema.columns WHERE table_schema = $1 AND table_name = $2 ORDER BY ordinal_position`,
    [SCHEMA, table_name]
  );
  console.log(`\n=== COLUMNS: ${table_name} ===`);
  for (const row of cols.rows) {
    console.log(`  ${row.column_name}  (${row.data_type})`);
  }
}

// 3. Show all data in each table
for (const { table_name } of tables.rows) {
  const data = await client.query(
    `SELECT * FROM "${SCHEMA}"."${table_name}"`
  );
  console.log(`\n=== DATA: ${table_name} (${data.rowCount} rows) ===`);
  if (data.rowCount === 0) {
    console.log("  (empty)");
  } else {
    for (const row of data.rows) {
      console.log(JSON.stringify(row));
    }
  }
}

await client.end();

